import{_ as a,o as t,c as o,a2 as n}from"./chunks/framework.7R1OEGYz.js";const u=JSON.parse('{"title":"The Ondol account","description":"","frontmatter":{},"headers":[],"relativePath":"internals/ondol-account.md","filePath":"internals/ondol-account.md"}'),s={name:"internals/ondol-account.md"};function i(r,e,c,d,l,h){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="the-ondol-account" tabindex="-1">The Ondol account <a class="header-anchor" href="#the-ondol-account" aria-label="Permalink to &quot;The Ondol account&quot;">​</a></h1><p>The Ondol account is a smart account at your own address. It uses EIP-7702 to place code at an existing address, and a passkey to authorize day-to-day calls.</p><h2 id="eip-7702-in-place" tabindex="-1">EIP-7702 in place <a class="header-anchor" href="#eip-7702-in-place" aria-label="Permalink to &quot;EIP-7702 in place&quot;">​</a></h2><p>A normal account is an EOA controlled by a secp256k1 key. EIP-7702 lets that address delegate to a contract implementation. The address keeps its history, its name, and its Dojang verification. It gains smart-account behavior at the same address.</p><p>On GIWA Sepolia the delegation shows up as a code designator. It reads <code>0xef0100</code> followed by the implementation address. Delegation can be cleared by authorizing the zero address, which was verified live during our probes.</p><h2 id="passkeys-authorize" tabindex="-1">Passkeys authorize <a class="header-anchor" href="#passkeys-authorize" aria-label="Permalink to &quot;Passkeys authorize&quot;">​</a></h2><p>Once delegated, day-to-day operations are authorized by a passkey, not the original key. A passkey is a WebAuthn P-256 credential in your device credential manager.</p><p><code>execute()</code> verifies the WebAuthn assertion on chain. It checks the assertion over the account challenge, then runs each call through the guard. The signature is verified through the P256VERIFY precompile, a native precompile on GIWA. The challenge is <code>keccak256(account, chainId, nonce, calls)</code>, so a signature is good for one account, one chain, one nonce, one batch.</p><p>Fork tests prove that a malicious relayer cannot tamper with a batch, replay a signature, or redirect it.</p><h2 id="v2-and-gasless-onboarding" tabindex="-1">V2 and gasless onboarding <a class="header-anchor" href="#v2-and-gasless-onboarding" aria-label="Permalink to &quot;V2 and gasless onboarding&quot;">​</a></h2><p>The current implementation is <code>OndolAccountV2</code>. It adds <code>initializeWithSig</code>, a signature-gated setup. A relayer can initialize a fresh account with an EIP-712 signature from the account&#39;s own key. The fresh account needs no gas.</p><p>The domain binds the chain id and the account address, so a setup signature cannot replay across chains or onto another account. Low-s is enforced, matching the malleability rule on the P-256 side.</p><p>V2 keeps the exact storage layout of v1. An account initialized under v1 re-delegates to v2 and keeps its passkey, nonce, and wiring with no re-initialization. The alice account was migrated live. <a href="https://sepolia-explorer.giwa.io/tx/0x2a24fa95278db11517d9af46e9b43d9046784d82ab1f1cdec0972bd6316598af" target="_blank" rel="noreferrer">View the re-delegation transaction.</a></p><p>Contract addresses are on the <a href="/docs/developers/contracts">Contracts and addresses</a> page.</p>',14)])])}const g=a(s,[["render",i]]);export{u as __pageData,g as default};
